body:
Create a `create-index.js` file in your project directory,
and copy and paste the following code into the file.```javascript
const { MongoClient } = require('mongodb');

// Connection URI
const uri = 'mongodb+srv://<username>:<password>@<cluster-url>';

// Create a new MongoClient
const client = new MongoClient(uri);

async function createSearchIndex() {
  try {
    await client.connect();
    const database = client.db('<databaseName>');

    // Create a MongoDB Search index on the objectId field
    await database.command({
      createSearchIndexes: '<collectionName>',
      indexes: [{
        name: '<indexName>',
        definition: {
          mappings: {
            dynamic: true | false,
            fields: {
              '<fieldName>': {
                type: 'objectId'
              }
            }
          }
        }
      }]
    });

    console.log('Successfully created Atlas Search index');
  } finally {
    await client.close();
  }
}

createSearchIndex().catch(console.error);
```Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.Atlas ClusterYour connection string should use the following format:```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```To learn more, see [Driver](connect-via-driver).Local or Self-ManagedYour connection string should use the
following format:```
mongodb://localhost:<port-number>/?directConnection=true
```To learn more, see [Connection Strings](manual/reference/connection-string).

